import React from 'react';
import type { ISkeletonText } from '@lmb-it/kitsconcerto-types';
import { Skeleton as PrimeSkeleton } from 'primereact/skeleton';
import { Flex } from '../../_compat';
import { ResponsiveElement, useSeparator } from "../../factory";


const SkeletonText: React.FC<ISkeletonText> = ({
                                                   lines = 3,
                                                   width = '100%',
                                                   spacing = '0.5rem',
                                                   isLoaded,
                                                   children,
                                                   variant,
                                                   style,
                                                   ...props
                                               }) => {
    const { cssProps, nativeProps } = useSeparator<Record<any, any>>(props);

    const lineArray = Array.from({ length: lines });

    if (isLoaded) {
        return (
            <Flex flexDirection="column" gap={spacing} {...style} {...nativeProps}>
                {children}
            </Flex>
        );
    }

    return (
        <Flex flexDirection="column" gap={spacing} {...style} {...nativeProps}>
            {lineArray.map((_, index) => (
                <PrimeSkeleton
                    key={index}
                    shape={'rectangle'}
                    width={'100%'}
                    className={props?.className}
                />
            ))}
        </Flex>
    );
};

export default SkeletonText;
